// myQRID Logo System — FROZEN MASTER
const MYQRID_LOGO_DARK  = "data:image/svg+xml;base64,";
const MYQRID_LOGO_LIGHT = "data:image/svg+xml;base64,";
const MYQRID_ICON       = "data:image/svg+xml;base64,";
const MYQRID_QR_DARK    = "data:image/svg+xml;base64,";
const MYQRID_QR_LIGHT   = "data:image/svg+xml;base64,";
const MYQRID_Q          = "data:image/svg+xml;base64,";
const MYQRID_LOGO       = MYQRID_LOGO_DARK;

function injectLogos() {
  document.querySelectorAll('img[id*="logo"],img[id*="Logo"],img[id*="splash"]').forEach(el => {
    if (!el.src || el.src === window.location.href || el.src.endsWith('/')) {
      el.src = MYQRID_LOGO_DARK; el.alt = el.alt || 'myQRID';
    }
  });
  document.querySelectorAll('img[id*="nav-logo"],img[data-logo="icon"]').forEach(el => {
    el.src = MYQRID_ICON; el.alt = 'myQRID';
  });
  document.querySelectorAll('img[data-logo="qr"]').forEach(el => { el.src = MYQRID_QR_DARK; });
  const fav = document.querySelector('link[rel*="icon"]');
  if (fav) fav.href = MYQRID_ICON;
}
document.addEventListener('DOMContentLoaded', injectLogos);
